// lib/core/errors/failure.dart тАФ every layer speaks this hierarchy
sealed class Failure {
  const Failure(this.message);
  final String message;
}

class NetworkFailure extends Failure { const NetworkFailure(super.message); }
class ServerFailure  extends Failure { const ServerFailure(super.message, this.statusCode); final int statusCode; }
class AuthFailure    extends Failure { const AuthFailure(super.message); }
class NotFoundFailure extends Failure { const NotFoundFailure(super.message); }
class ValidationFailure extends Failure {
  const ValidationFailure(super.message, this.fields);
  final Map<String, String> fields;
}
class UnknownFailure extends Failure { const UnknownFailure(super.message); }

// lib/core/result/result.dart тАФ Ok(T) or Err(E)
sealed class Result<T, E> {
  const Result();

  bool get isOk => this is Ok<T, E>;
  bool get isErr => this is Err<T, E>;

  R fold<R>({required R Function(T value) ok, required R Function(E error) err}) =>
      switch (this) {
        Ok<T, E>(:final value) => ok(value),
        Err<T, E>(:final error) => err(error),
      };

  Result<R, E> map<R>(R Function(T) fn) => switch (this) {
    Ok<T, E>(:final value) => Ok(fn(value)),
    Err<T, E>(:final error) => Err(error),
  };
}

class Ok<T, E>  extends Result<T, E> { const Ok(this.value);  final T value; }
class Err<T, E> extends Result<T, E> { const Err(this.error); final E error; }

// lib/core/result/guard.dart тАФ wrap try/catch into Result
Future<Result<T, Failure>> guard<T>(Future<T> Function() action) async {
  try {
    return Ok(await action());
  } on DioException catch (e) {
    return Err(_dioToFailure(e));
  } on Exception catch (e) {
    return Err(UnknownFailure(e.toString()));
  }
}

Failure _dioToFailure(DioException e) => switch (e.response?.statusCode) {
  401 => const AuthFailure('Not authenticated'),
  404 => NotFoundFailure(e.message ?? 'Not found'),
  int status when status >= 500 => ServerFailure('Server error', status),
  _ => NetworkFailure(e.message ?? 'Network error'),
};

// ============ Consumers use Result end-to-end ============
// Repository:
class UserRepositoryImpl implements UserRepository {
  UserRepositoryImpl(this._api);
  final Dio _api;

  @override
  Future<Result<User, Failure>> getById(int id) =>
      guard(() async {
        final r = await _api.get('/users/$id');
        return User.fromJson(r.data);
      });
}

// ViewModel:
class UserViewModel extends ChangeNotifier {
  UserViewModel(this._repo);
  final UserRepository _repo;
  User? user;
  Failure? error;

  Future<void> load(int id) async {
    (await _repo.getById(id)).fold(
      ok:  (u) => user = u,
      err: (e) => error = e,
    );
    notifyListeners();
  }
}

// UI:
switch (vm.error) {
  case AuthFailure(): _navigateToLogin();
  case NotFoundFailure(): _showNotFound();
  case ServerFailure(:final statusCode): _showServerError(statusCode);
  case NetworkFailure(): _showOfflineBanner();
  case ValidationFailure(:final fields): _highlightErrors(fields);
  case UnknownFailure() || null: _showGeneric();
}

// Notice: every layer speaks the SAME typed-error language.
// No random Exception messages leaking. The compiler enforces exhaustive handling.

// lib/core/network/dio_factory.dart
Dio createDio({required EnvConfig env, required AuthService auth, required AppLogger log}) {
  final dio = Dio(BaseOptions(
    baseUrl: env.apiBaseUrl,
    connectTimeout: const Duration(seconds: 15),
    receiveTimeout: const Duration(seconds: 30),
    headers: {'Content-Type': 'application/json'},
  ));

  dio.interceptors.addAll([
    // Attach auth token to every request
    InterceptorsWrapper(
      onRequest: (options, handler) {
        final token = auth.token;
        if (token != null) options.headers['Authorization'] = 'Bearer $token';
        handler.next(options);
      },
    ),

    // Log requests + responses (only in dev)
    if (kDebugMode) LogInterceptor(requestBody: true, responseBody: true),

    // Retry on transient failures
    RetryInterceptor(
      dio: dio,
      maxRetries: 3,
      retryDelays: const [Duration(seconds: 1), Duration(seconds: 3), Duration(seconds: 5)],
    ),

    // Refresh token on 401 (advanced тАФ omitted for brevity)
  ]);

  return dio;
}
